/* eslint-disable no-unused-vars */
import React from 'react';
import defs from './../defs';

const ProgressBar = props => {
  const { percent } = props;

  const label = () => {
    if (percent >= 0 && percent <= 20) {
      return { label: 'افتضاح', color: defs.colors.danger };
    } else if (percent >= 20 && percent <= 50) {
      return { label: 'تقریبا قوی', color: defs.colors.warning };
    } else if (percent >= 50 && percent <= 70) {
      return { label: 'قوی', color: defs.colors.info };
    } else {
      return { label: 'قوی+ 😅', color: defs.colors.success };
    }
  }
  const getLabel = label();

  const containerStyles = {
    height: 5,
    width: '100%',
    backgroundColor: "#e0e0de",
    borderRadius: 50,
    marginTop: 10,
    textAlign: 'left',
  }

  const fillerStyles = {
    height: '100%',
    width: `${percent}%`,
    backgroundColor: getLabel.color,
    borderRadius: 'inherit',
  }

  const labelStyles = {
    color: getLabel.color,
    fontWeight: 'bold',
    display: 'inline',
    verticalAlign: 'middle',
    fontSize: '.7em',
  }

  return (
    <div style={containerStyles}>
      <div style={fillerStyles}></div>
      <span style={labelStyles}>{`${getLabel.label}`}</span>
    </div>
  );
}

export default ProgressBar;